const operations = $input.first().json.output;
const lines      = [...$node['Code: Decode File'].json['lines']];
const totalLines = $node['Code: Decode File'].json['total_lines'];
if (!Array.isArray(operations)) { return [{ json: { valid: false, error: 'Editor output is not an array' } }]; }
const skippedOps = [];
const normalized = [];
for (const op of operations) {
  let norm = null;
  if (op.operation === 'replace') {
    if (!Number.isInteger(op.line_number)) { skippedOps.push({ ...op, reason: 'replace: missing line_number' }); continue; }
    norm = { operation: 'replace', line_start: op.line_number, line_end: op.line_number, new_lines: [op.new_text !== undefined ? String(op.new_text) : ''] };
  } else if (op.operation === 'replace_range') {
    if (!Number.isInteger(op.line_start) || !Number.isInteger(op.line_end)) { skippedOps.push({ ...op, reason: 'replace_range: missing range' }); continue; }
    const newLines = Array.isArray(op.new_lines) ? op.new_lines.map(String) : (op.new_text !== undefined ? [String(op.new_text)] : []);
    norm = { operation: 'replace_range', line_start: op.line_start, line_end: op.line_end, new_lines: newLines };
  } else if (op.operation === 'insert_after') {
    if (!Number.isInteger(op.line_number)) { skippedOps.push({ ...op, reason: 'insert_after: missing line_number' }); continue; }
    const newLines = Array.isArray(op.new_lines) ? op.new_lines.map(String) : [];
    if (newLines.length === 0) { skippedOps.push({ ...op, reason: 'insert_after: empty new_lines' }); continue; }
    norm = { operation: 'insert_after', line_start: op.line_number, line_end: op.line_number, new_lines: newLines };
  } else if (op.operation === 'delete') {
    const start = op.line_number || op.line_start;
    const end   = op.line_end || start;
    if (!Number.isInteger(start)) { skippedOps.push({ ...op, reason: 'delete: missing line' }); continue; }
    norm = { operation: 'delete', line_start: start, line_end: end, new_lines: [] };
  } else { skippedOps.push({ ...op, reason: `unknown operation: ${op.operation}` }); continue; }
  if (norm.line_start < 1 || norm.line_start > totalLines) { skippedOps.push({ ...op, reason: `line_start out of range` }); continue; }
  if (norm.line_end < 1 || norm.line_end > totalLines) { skippedOps.push({ ...op, reason: `line_end out of range` }); continue; }
  if (norm.new_lines.some(l => l.includes('\n'))) { skippedOps.push({ ...op, reason: 'embedded newline' }); continue; }
  if (norm.operation === 'replace' && norm.new_lines[0] === lines[norm.line_start - 1]) { skippedOps.push({ ...op, reason: 'identical to original' }); continue; }
  normalized.push(norm);
}
normalized.sort((a, b) => a.line_start - b.line_start);
const validOps = [];
let lastEnd = 0;
for (const op of normalized) {
  if (op.line_start <= lastEnd) { skippedOps.push({ ...op, reason: `overlapping range` }); continue; }
  lastEnd = op.line_end;
  validOps.push(op);
}
if (validOps.length === 0) { return [{ json: { valid: false, error: 'No valid operations', skipped: skippedOps } }]; }
validOps.sort((a, b) => b.line_start - a.line_start);
for (const op of validOps) {
  const startIdx = op.line_start - 1;
  const count    = op.line_end - op.line_start + 1;
  if (op.operation === 'replace' || op.operation === 'replace_range') { lines.splice(startIdx, count, ...op.new_lines); }
  else if (op.operation === 'delete') { lines.splice(startIdx, count); }
  else if (op.operation === 'insert_after') { lines.splice(startIdx + 1, 0, ...op.new_lines); }
}
const updatedContent    = lines.join('\n') + '\n';
const updatedContentB64 = Buffer.from(updatedContent).toString('base64');
const operationsLog = validOps.map(op => ({ operation: op.operation, line_start: op.line_start, line_end: op.line_end, new_lines_count: op.new_lines.length }));
return [{ json: { valid: true, updated_content: updatedContent, updated_content_b64: updatedContentB64, applied_count: validOps.length, skipped_count: skippedOps.length, skipped_ops: skippedOps, operations_log: operationsLog } }];

