const runDate     = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const issues      = $('Agent 1: QA Analysis').first().json.output || [];
const applyResult = $('Code: Apply Edits').first().json;
const issueLines = issues.map(issue => { const range = issue.line_start ? `Lines ${issue.line_start}-${issue.line_end}` : `Line ${issue.line_number}`; return `- **${range}** \`[${issue.issue_type}]\` \`${issue.priority}\` -- ${issue.description}`; }).join('
');
const opsLog = (applyResult.operations_log || []).map(op => { const range = op.line_start === op.line_end ? `Line ${op.line_start}` : `Lines ${op.line_start}-${op.line_end}`; return `- \`${op.operation}\` ${range}` + (op.new_lines_count > 0 ? ` -> ${op.new_lines_count} line(s)` : ''); }).join('
');
const skippedSection = applyResult.skipped_count > 0 ? '
### Skipped operations
' + applyResult.skipped_ops.map(op => `- \`${op.operation}\` line ${op.line_start || op.line_number}: ${op.reason}`).join('
') + '
' : '';
const newEntry = `## Run: ${runDate}
` + `**Issues found:** ${issues.length} | **Applied:** ${applyResult.applied_count} | **Skipped:** ${applyResult.skipped_count}

` + `### Issues detected
${issueLines || '_none_'}

` + `### Operations applied
${opsLog || '_none_'}
` + skippedSection + `
---

`;
let existingContent = ''; let reportSha = undefined;
try { const reportData = $('GitHub: Get QA Report').first().json; if (reportData && reportData.content) { const cleanB64 = reportData.content.replace(/
/g, ''); existingContent = Buffer.from(cleanB64, 'base64').toString('utf-8'); reportSha = reportData.sha; } } catch (e) {}
const header = '# QA Run Log

';
const prevContent = existingContent.startsWith('# QA Run Log') ? existingContent.slice(header.length) : existingContent;
const fullContent = header + newEntry + prevContent;
const contentB64  = Buffer.from(fullContent).toString('base64');
const bodyObj = { message: `AI QA: log run ${runDate}`, content: contentB64 };
if (reportSha) bodyObj.sha = reportSha;
return [{ json: { report_body: JSON.stringify(bodyObj) } }];
